BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pattern ?name WHERE {
  { 
    ?pattern rdf:type vocab:sequencer .
  } UNION {
    ?pattern rdf:type vocab:integration .
  } UNION {
    ?pattern rdf:type vocab:alloc .
  } UNION {
    ?pattern rdf:type vocab:dependency .
  } UNION {
    ?pattern rdf:type vocab:assembly .
  }
  OPTIONAL { ?pattern vocab:NamedElement_name ?name . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?patternType ?patternName WHERE {
  ?pattern rdf:type ?patternType ;
           vocab:NamedElement_name ?patternName .

  FILTER(CONTAINS(LCASE(STR(?patternName)), LCASE("pattern")))
  FILTER(
    (?patternType = vocab:block || ?patternType = vocab:package)
  )
}
ORDER BY ?patternType ?patternName
LIMIT 25
